import{_ as t,c as r,o as a,aj as d}from"./chunks/framework.guNMSiFm.js";const p=JSON.parse('{"title":"Filters","description":"","frontmatter":{},"headers":[],"relativePath":"blockchain/filters.md","filePath":"blockchain/filters.md","lastUpdated":1777621302000}'),i={name:"blockchain/filters.md"};function o(c,e,n,l,s,h){return a(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h1><p>Filters narrow event streams and trigger conditions. The current top-level event filter is <code>EventFilterBox</code>, which can match these event families:</p><ul><li><code>Pipeline</code></li><li><code>Data</code></li><li><code>Time</code></li><li><code>ExecuteTrigger</code></li><li><code>TriggerCompleted</code></li></ul><p>Use the narrowest filter that matches the workflow. Broad filters such as <code>DataEventFilter::Any</code> are useful for diagnostics, but they make every event pay the cost of trigger or subscriber matching.</p><h2 id="data-event-filters" tabindex="-1">Data Event Filters <a class="header-anchor" href="#data-event-filters" aria-label="Permalink to &quot;Data Event Filters&quot;">​</a></h2><p><code>DataEventFilter</code> matches ledger data events. Its current variants include:</p><table tabindex="0"><thead><tr><th>Variant</th><th>Event family</th></tr></thead><tbody><tr><td><code>Any</code></td><td>Any data event</td></tr><tr><td><code>Peer</code></td><td>Peer lifecycle events</td></tr><tr><td><code>Domain</code></td><td>Domain lifecycle and metadata events</td></tr><tr><td><code>Account</code></td><td>Account lifecycle, metadata, alias, and identity events</td></tr><tr><td><code>Asset</code></td><td>Asset balance and metadata events</td></tr><tr><td><code>AssetDefinition</code></td><td>Asset definition lifecycle, policy, and metadata events</td></tr><tr><td><code>Nft</code></td><td>NFT lifecycle and metadata events</td></tr><tr><td><code>Rwa</code></td><td>Real-world-asset lifecycle events</td></tr><tr><td><code>Trigger</code></td><td>Trigger lifecycle and metadata events</td></tr><tr><td><code>Role</code></td><td>Role lifecycle events</td></tr><tr><td><code>Configuration</code></td><td>On-chain configuration events</td></tr><tr><td><code>Executor</code></td><td>Runtime executor events</td></tr><tr><td><code>Proof</code></td><td>Proof verification lifecycle events</td></tr><tr><td><code>Confidential</code></td><td>Confidential asset events</td></tr><tr><td><code>VerifyingKey</code></td><td>Verifying-key registry events</td></tr><tr><td><code>RuntimeUpgrade</code></td><td>Runtime upgrade events</td></tr><tr><td><code>Soradns</code></td><td>Resolver directory governance events</td></tr><tr><td><code>Sorafs</code></td><td>SoraFS gateway compliance events</td></tr><tr><td><code>SpaceDirectory</code></td><td>Space Directory manifest lifecycle events</td></tr><tr><td><code>Escrow</code></td><td>Native asset escrow lifecycle events</td></tr><tr><td><code>Offline</code></td><td>Offline settlement events</td></tr><tr><td><code>Oracle</code></td><td>Oracle feed events</td></tr><tr><td><code>Social</code></td><td>Viral incentive events</td></tr><tr><td><code>Bridge</code></td><td>Bridge events</td></tr><tr><td><code>Governance</code></td><td>Governance events when the governance feature is enabled</td></tr></tbody></table><p>Most concrete filters also allow an optional ID matcher and an event-set mask. For example, an asset filter can match one asset or one class of asset events, while a trigger filter can match a trigger ID and a trigger event set.</p><h2 id="pipeline-filters" tabindex="-1">Pipeline Filters <a class="header-anchor" href="#pipeline-filters" aria-label="Permalink to &quot;Pipeline Filters&quot;">​</a></h2><p>Pipeline filters match processing events such as block, transaction, merge, and witness events. Use them for operational subscriptions, block-processing dashboards, and triggers that react to pipeline state rather than ledger data objects.</p><h2 id="trigger-filters" tabindex="-1">Trigger Filters <a class="header-anchor" href="#trigger-filters" aria-label="Permalink to &quot;Trigger Filters&quot;">​</a></h2><p>Triggers store their condition as an <code>EventFilterBox</code>. A trigger action also stores:</p><ul><li>an executable</li><li>a repetition policy</li><li>an authority account</li><li>an optional time-trigger retry policy</li><li>metadata</li></ul><p>The trigger authority must have the permissions required by the executable. Prefer dedicated technical accounts for long-lived triggers.</p><h2 id="query-filters" tabindex="-1">Query Filters <a class="header-anchor" href="#query-filters" aria-label="Permalink to &quot;Query Filters&quot;">​</a></h2><p>Query filters are separate from event filters. Iterable queries can expose predicate and selector support. Use query-specific typed filters from the SDK so the filter input matches the query output type.</p><p>See also:</p><ul><li><a href="/iroha-2-docs/blockchain/events.html">Events</a></li><li><a href="/iroha-2-docs/blockchain/triggers.html">Triggers</a></li><li><a href="/iroha-2-docs/blockchain/queries.html">Queries</a></li><li><a href="/iroha-2-docs/reference/queries.html">Query reference</a></li></ul>',18)])])}const u=t(i,[["render",o]]);export{p as __pageData,u as default};
